class Solution:
    def largestInteger(self, num: int) -> int:
        s = list(str(num))
        n = len(s)
        for i in range(n):
            for j in range(i + 1, n):
                if (int(s[i]) & 1) == (int(s[j]) & 1) and s[j] > s[i]:
                    s[i], s[j] = s[j], s[i]
        return int(''.join(s))
```
